import json
import os
import pytest
from pathlib import Path

import yaml


def load_schema():
    """Load the results schema from the contracts directory."""
    schema_path = Path(__file__).parent.parent.parent / "contracts" / "results.schema.yaml"
    if not schema_path.exists():
        pytest.fail(f"Schema file not found: {schema_path}")
    with open(schema_path, "r") as f:
        return yaml.safe_load(f)


def load_results_file():
    """Load the performance results file generated by the pipeline."""
    results_path = Path(__file__).parent.parent.parent / "data" / "processed" / "performance_results.json"
    if not results_path.exists():
        pytest.fail(f"Results file not found: {results_path}. Run the evaluation pipeline first.")
    with open(results_path, "r") as f:
        return json.load(f)


def test_performance_schema_contains_latency_and_ram():
    """
    Contract test: Verify `data/processed/performance_results.json` contains
    `latency_ms` and `peak_ram_mb` fields as defined in results.schema.yaml.
    """
    schema = load_schema()
    results = load_results_file()

    # The schema might define the structure at the top level or nested.
    # We check the top-level keys first, then look for common nested structures.
    required_fields = ["latency_ms", "peak_ram_mb"]

    found_fields = {}
    missing_fields = []

    # Check top level
    for field in required_fields:
        if field in results:
            found_fields[field] = True
        else:
            missing_fields.append(field)

    # If missing at top level, check if it's a list of results or nested dict
    if missing_fields:
        # Check if results is a list
        if isinstance(results, list) and len(results) > 0:
            first_item = results[0]
            for field in required_fields:
                if isinstance(first_item, dict) and field in first_item:
                    found_fields[field] = True
                else:
                    # Check nested common keys like 'metrics', 'performance'
                    for key in ["metrics", "performance", "data"]:
                        if key in first_item and isinstance(first_item[key], dict):
                            if field in first_item[key]:
                                found_fields[field] = True
                                break
            # Re-evaluate missing
            missing_fields = [f for f in required_fields if f not in found_fields]

    if missing_fields:
        pytest.fail(f"Results file missing required fields for performance contract: {missing_fields}. "
                    f"Found keys: {list(results.keys()) if isinstance(results, dict) else 'List of items'}")

    # Verify types if possible
    if "latency_ms" in found_fields:
        # Determine where the value is
        val = results.get("latency_ms")
        if not val:
            val = results[0].get("latency_ms") if isinstance(results, list) else None
            if not val and "metrics" in results:
                val = results["metrics"].get("latency_ms")
        assert isinstance(val, (int, float)), f"latency_ms must be a number, got {type(val)}"

    if "peak_ram_mb" in found_fields:
        val = results.get("peak_ram_mb")
        if not val:
            val = results[0].get("peak_ram_mb") if isinstance(results, list) else None
            if not val and "metrics" in results:
                val = results["metrics"].get("peak_ram_mb")
        assert isinstance(val, (int, float)), f"peak_ram_mb must be a number, got {type(val)}"